class Solution {
public:
    string shortestPalindrome(string s) {
        string rs = s;
        reverse(rs.begin(), rs.end());
        string t = s + '#' + rs;
        vector<int> pi(t.size());
        for (int i = 1; i < (int)t.size(); i++) {
            int j = pi[i - 1];
            while (j && t[i] != t[j]) j = pi[j - 1];
            if (t[i] == t[j]) j++;
            pi[i] = j;
        }
        int k = pi.back();
        return rs.substr(0, s.size() - k) + s;
    }
};

