char* shortestPalindrome(const char* s) {
    int n = (int)strlen(s);
    if (!n) return strdup("");
    char* t = malloc(2*n + 2);
    strcpy(t, s); t[n] = '#'; reverseCopy(t+n+1, s);
    int m = 2*n+1;
    int* pi = calloc(m, sizeof(int));
    for (int i=1;i<m;i++) {
        int j=pi[i-1];
        while (j && t[i]!=t[j]) j=pi[j-1];
        if (t[i]==t[j]) j++;
        pi[i]=j;
    }
    int k=pi[m-1];
    char* out = malloc(n + (n-k) + 1);
    for (int i=n-1;i>=k;i--) out[n-1-i]=s[i];
    strcpy(out+(n-k), s);
    free(t); free(pi);
    return out;
}
